import{_ as e,a as i,b as t,c as l,d as o,e as r,f as n}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as d,o as s,c,a2 as p}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Aggiungere un canale Discord","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/discord.md","filePath":"it-IT/upload/discord.md","lastUpdated":1781962217000}'),h={name:"it-IT/upload/discord.md"};function u(m,a,g,b,v,f){return s(),c("div",null,[...a[0]||(a[0]=[p('<h1 id="aggiungere-un-canale-discord" tabindex="-1">Aggiungere un canale Discord <a class="header-anchor" href="#aggiungere-un-canale-discord" aria-label="Permalink to &quot;Aggiungere un canale Discord&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Discord</td><td>Per creare server, canale e applicazione sviluppatore.</td></tr><tr><td>Server Discord</td><td>Il bot deve entrare in un server prima di accedere a un canale.</td></tr><tr><td>Canale testuale</td><td>Immagini e file verranno inviati qui.</td></tr><tr><td>Discord Developer Portal</td><td>Per creare applicazione, bot e ottenere il <code>Bot Token</code>.</td></tr></tbody></table><h2 id="dove-aggiungerlo" tabindex="-1">Dove aggiungerlo <a class="header-anchor" href="#dove-aggiungerlo" aria-label="Permalink to &quot;Dove aggiungerlo&quot;">​</a></h2><ol><li>Apri Impostazioni di sistema.</li><li>Vai a Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale in alto a destra.</li><li>Seleziona <code>Discord</code>.</li></ol><h2 id="riferimento-campi" tabindex="-1">Riferimento campi <a class="header-anchor" href="#riferimento-campi" aria-label="Permalink to &quot;Riferimento campi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Funzione</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>Nome canale</td><td>Nome riconoscibile, per esempio <code>Discord Primary</code>.</td><td>Sì</td></tr><tr><td>Bot Token</td><td>Token del bot Discord.</td><td>Sì</td></tr><tr><td>Channel ID</td><td>ID del canale testuale di destinazione.</td><td>Sì</td></tr><tr><td>Proxy URL (opzionale)</td><td>Usalo solo se l&#39;accesso al CDN Discord è instabile. Inserisci l&#39;URL completo con <code>https://</code>.</td><td>No</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="_1-crea-server-e-canale-testuale" tabindex="-1">1. Crea server e canale testuale <a class="header-anchor" href="#_1-crea-server-e-canale-testuale" aria-label="Permalink to &quot;1. Crea server e canale testuale&quot;">​</a></h3><ol><li>Apri Discord.</li><li>Crea un nuovo server o usa un server esistente di tua proprietà.</li><li>Crea un canale testuale nel server.</li></ol><p><img src="'+e+'" alt="Crea server" loading="lazy"></p><h3 id="_2-crea-un-bot-nel-discord-developer-portal" tabindex="-1">2. Crea un bot nel Discord Developer Portal <a class="header-anchor" href="#_2-crea-un-bot-nel-discord-developer-portal" aria-label="Permalink to &quot;2. Crea un bot nel Discord Developer Portal&quot;">​</a></h3><ol><li>Apri Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Clicca su <code>New Application</code>.</li><li>Inserisci il nome dell&#39;applicazione e creala.</li><li>Apri la pagina <code>Bot</code> dalla barra laterale.</li><li>Genera o resetta il token nella pagina <code>Bot</code>.</li><li>Salva il token.</li></ol><p>Questo token è il <code>Bot Token</code> da inserire in ImgBed.</p><p><img src="'+i+'" alt="Visualizza Bot Token" loading="lazy"></p><h3 id="_3-genera-un-link-oauth2-e-installa-il-bot" tabindex="-1">3. Genera un link OAuth2 e installa il bot <a class="header-anchor" href="#_3-genera-un-link-oauth2-e-installa-il-bot" aria-label="Permalink to &quot;3. Genera un link OAuth2 e installa il bot&quot;">​</a></h3><ol><li>Apri <code>OAuth2</code> dalla barra laterale.</li><li>Sotto scopes seleziona <code>bot</code>.</li><li>Nell&#39;area permessi abilita:</li></ol><table tabindex="0"><thead><tr><th>Permesso</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>View Channels</td><td>Sì</td></tr><tr><td>Send Messages</td><td>Sì</td></tr><tr><td>Attach Files</td><td>Sì</td></tr><tr><td>Read Message History</td><td>Sì</td></tr></tbody></table><ol start="4"><li>In fondo alla pagina controlla che il tipo di integrazione sia <code>Guild Install</code>.</li><li>Copia l&#39;URL generato.</li><li>Aprilo nel browser.</li><li>Seleziona il server di destinazione.</li><li>Completa l&#39;autorizzazione.</li></ol><p><img src="'+t+'" alt="Seleziona permessi bot in OAuth2" loading="lazy"></p><p><img src="'+l+'" alt="Invita il bot nel canale" loading="lazy"></p><h3 id="_4-abilita-modalita-sviluppatore-e-copia-channel-id" tabindex="-1">4. Abilita modalità sviluppatore e copia Channel ID <a class="header-anchor" href="#_4-abilita-modalita-sviluppatore-e-copia-channel-id" aria-label="Permalink to &quot;4. Abilita modalità sviluppatore e copia Channel ID&quot;">​</a></h3><ol><li>Clicca sull&#39;icona ingranaggio accanto al tuo avatar in basso a sinistra.</li><li>Apri Advanced dalla barra laterale.</li><li>Abilita Developer Mode.</li><li>Torna al canale testuale di destinazione.</li><li>Clicca con il tasto destro sul nome del canale.</li><li>Clicca su Copy Channel ID.</li></ol><p>Il numero copiato è il <code>Channel ID</code> richiesto da ImgBed.</p><p><img src="'+o+'" alt="Abilita modalità sviluppatore" loading="lazy"></p><p><img src="'+r+'" alt="Copia Channel ID" loading="lazy"></p><h3 id="_5-compila-il-canale-discord-in-imgbed" tabindex="-1">5. Compila il canale Discord in ImgBed <a class="header-anchor" href="#_5-compila-il-canale-discord-in-imgbed" aria-label="Permalink to &quot;5. Compila il canale Discord in ImgBed&quot;">​</a></h3><p>Torna alla finestra di configurazione e compila:</p><table tabindex="0"><thead><tr><th>Campo UI</th><th>Valore</th></tr></thead><tbody><tr><td>Nome canale</td><td>Nome personalizzato, per esempio <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token salvato dalla pagina <code>Bot</code> del Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID copiato da Discord.</td></tr><tr><td>Proxy URL (opzionale)</td><td>Solo se serve, per esempio <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Quando hai finito, salva.</p><p><img src="'+n+`" alt="Aggiungi configurazione Discord" loading="lazy"></p><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controllo</th><th>Come verificare</th></tr></thead><tbody><tr><td>Scheda canale</td><td>Dopo il salvataggio compare una scheda Discord.</td></tr><tr><td>Canale abilitabile</td><td>L&#39;interruttore Attivo resta acceso.</td></tr><tr><td>Configurazione salvata</td><td>La vista dettaglio mostra Bot Token e Channel ID salvati.</td></tr><tr><td>Upload funzionante</td><td>Carica un&#39;immagine di prova e verifica che compaia nel canale testuale Discord.</td></tr></tbody></table><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Crea un server Discord</span></span>
<span class="line"><span>-&gt; Crea un canale testuale</span></span>
<span class="line"><span>-&gt; Crea un bot nel Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Salva il Bot Token dalla pagina Bot</span></span>
<span class="line"><span>-&gt; In OAuth2 seleziona bot, View Channels, Send Messages, Attach Files e Read Message History</span></span>
<span class="line"><span>-&gt; Copia l&#39;URL generato e autorizza il bot nel server di destinazione</span></span>
<span class="line"><span>-&gt; Verifica che il canale testuale conceda gli stessi permessi</span></span>
<span class="line"><span>-&gt; Abilita Developer Mode</span></span>
<span class="line"><span>-&gt; Clicca destro sul canale testuale e copia Channel ID</span></span>
<span class="line"><span>-&gt; Inserisci Bot Token e Channel ID in ImgBed</span></span>
<span class="line"><span>-&gt; Salva e carica un&#39;immagine di prova</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const z=d(h,[["render",u]]);export{_ as __pageData,z as default};
